mapper.sql:
SELECT A.* , (SELECT MAX(INSERTURKEY) FROM TWORK_INFO_IB_HD B WHERE A.CTKEY = B.CTKEY AND A.INSERTDATE = B.INSERTDATE) AS INSERTURKEY , (SELECT MAX(UPDATEURKEY) FROM TWORK_INFO_IB_HD B WHERE A.CTKEY = B.CTKEY AND A.UPDATEDATE = B.UPDATEDATE) AS UPDATEURKEY , (SELECT URNM FROM TADMIN_MST_UR WHERE URKEY = (SELECT MAX(INSERTURKEY) FROM TWORK_INFO_IB_HD B WHERE A.CTKEY = B.CTKEY AND A.INSERTDATE = B.INSERTDATE)) AS INSERTURKEY_NAME , (SELECT URNM FROM TADMIN_MST_UR WHERE URKEY = (SELECT MAX(UPDATEURKEY) FROM TWORK_INFO_IB_HD B WHERE A.CTKEY = B.CTKEY AND A.UPDATEDATE = B.UPDATEDATE)) AS UPDATEURKEY_NAME FROM (SELECT A.IBHDTYPE ,A.CTKEY ||';'|| 'IBHDTYPE' ||';'|| A.IBHDTYPE AS IBHDTYPE_DESC ,A.OWKEY ,A.ICGRKEY ,D.ICGRNAME ,A.ACKEY ,A.ACNAME ,MIN(A.IBCONFIRMDATE) AS IBCONFIRMDATE ,MIN(A.IBCLOSINGDATE) AS IBCLOSINGDATE ,A.COMMENTS1 ,A.COMMENTS2 ,MAX(A.WKSTATUS) AS WKSTATUS ,A.CTKEY ||';'|| 'IB_WKSTATUS' ||';'|| MAX(A.WKSTATUS) AS WKSTATUS_DESC ,A.UDF1 ,A.UDF2 ,A.UDF3 ,MAX(A.INSERTDATE) AS INSERTDATE ,MAX(A.UPDATEDATE) AS UPDATEDATE ,A.IBHDDATE ,A.CTKEY ,A.IBEXPECTDATE ,A.PACKAGEORDERKEY ,A.WAYBILLNO ,A.POHDKEY ,A.STORE_KEY ,B.STORE_NAME ,A.TEMPERATURE ,A.PLQTY ,A.EXTERNORDERKEY ,A.EXTERNORDERKEY2 ,E.URKEY ,E.URKEY AS URKEY_DESC ,A.FR_CTKEY ,F.CTNAME AS FR_CTNAME ,G.OWNAME FROM TWORK_INFO_IB_HD A LEFT JOIN TWORK_MST_STORE B ON A.CTKEY = B.CTKEY AND A.STORE_KEY = B.STORE_KEY AND A.DCKEY = B.DCKEY LEFT JOIN TWORK_MST_AC C ON A.CTKEY = C.CTKEY AND A.ACKEY = C.ACKEY AND A.OWKEY = C.OWKEY LEFT JOIN TWORK_MST_ICGR D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND A.ICGRKEY = D.ICGRKEY LEFT JOIN TWORK_MST_ACXUR E ON A.CTKEY = E.CTKEY AND A.ACKEY = E.ACKEY AND A.LOGGRPCD = E.LOGGRPCD AND A.OWKEY = E.OWKEY LEFT JOIN TWORK_MST_CT F ON A.FR_CTKEY = F.CTKEY INNER JOIN TWORK_MST_OW G ON A.OWKEY = G.OWKEY WHERE A.CTKEY = '100' AND A.IBHDTYPE = '10'
AND #{SEARCH_CONDITION}
AND A.IBHDKEY = #{ibhdkey}
AND A.IBHDKEY IN
#{ibhdkeyList}
GROUP BY A.IBHDTYPE ,A.OWKEY ,A.ICGRKEY ,D.ICGRNAME ,A.ACKEY ,A.ACNAME -- ,A.IBCONFIRMDATE -- ,A.IBCLOSINGDATE ,A.COMMENTS1 ,A.COMMENTS2 ,A.UDF1 ,A.UDF2 ,A.UDF3 ,A.IBHDDATE ,A.CTKEY ,A.IBEXPECTDATE ,A.PACKAGEORDERKEY ,A.WAYBILLNO ,A.POHDKEY ,A.STORE_KEY ,B.STORE_NAME ,A.TEMPERATURE ,A.PLQTY ,A.EXTERNORDERKEY ,A.EXTERNORDERKEY2 ,E.URKEY ,E.URKEY ,A.FR_CTKEY ,F.CTNAME ,G.OWNAME ) A

SELECT C.CTKEY , B.EXTERNORDERKEY , B.EXTERNORDERLINENUM , B.SN , B.CFQTY , B.IBNRCD , C.IBCONFIRMDATE , C.PRODUCTLOT , B.NET_WGT , C.ATTRIBUTE3 , C.EXPIREDATE , C.PRODUCTDATE , A.ICKEY , D.ICNAME , D.SPEC , A.UOM , A.CTKEY || ';' || 'ICUTTYPE' ||';'|| A.UOM AS UOM_DESC , B.TO_IVATKEY , A.IBHDKEY , A.IBDTKEY , A.LOGGRPCD , A.OWKEY , A.TO_LCKEY , A.TO_ULCKEY , A.ICUTKEY , B.ILBHSKEY , B.INSERTDATE , B.INSERTURKEY , (SELECT URNM FROM TADMIN_MST_UR WHERE URKEY = B.INSERTURKEY) AS INSERTURKEY_NAME , B.UPDATEDATE , B.UPDATEURKEY , (SELECT URNM FROM TADMIN_MST_UR WHERE URKEY = B.UPDATEURKEY) AS UPDATEURKEY_NAME FROM TWORK_INFO_IB_DT A , TWORK_INFO_IBCF_DT B , TWORK_INFO_IVAT C , TWORK_MST_IC D WHERE A.CTKEY = B.CTKEY AND A.EXTERNORDERKEY = B.EXTERNORDERKEY AND A.EXTERNORDERLINENUM = B.EXTERNORDERLINENUM AND B.CTKEY = C.CTKEY AND B.TO_IVATKEY = C.IVATKEY AND A.CTKEY = D.CTKEY AND A.ICKEY = D.ICKEY AND A.OWKEY = D.OWKEY AND A.CTKEY = #{ctkey} AND A.EXTERNORDERKEY = #{externorderkey} AND A.EXTERNORDERLINENUM = #{externorderlinenum}
AND A.LOGGRPCD = #{loggrpcd}
ORDER BY B.SN

SELECT A.IBHDKEY ,A.IBDTKEY ,A.OWKEY ,G.OWNAME ,A.ICKEY ,A.ICUTKEY ,1 AS LABELQTY ,I.TTQTY / E.ICUTQTY AS CFQTY ,A.UOM ,A.CTKEY || ';' || 'ICUTTYPE' ||';'|| A.UOM AS UOM_DESC ,A.WKSTATUS ,A.CTKEY || ';' || 'TA_WKSTATUS' ||';'|| A.WKSTATUS AS WKSTATUS_DESC ,A.TO_LCKEY ,A.TO_ULCKEY ,A.TO_IVATKEY ,B.PRODUCTDATE ,B.EXPIREDATE ,B.IBCONFIRMDATE ,C.COSTPRICE ,C.IBNRCD ,A.CTKEY || ';' || 'PM012' ||';'|| C.IBNRCD AS IBNRCD_DESC ,F.ICNAME ,F.SPEC ,A.INSERTDATE ,A.INSERTURKEY ,A.UPDATEDATE ,A.UPDATEURKEY ,H.IBEXPECTDATE ,C.EXQTY - C.CFQTY AS RJQTY ,A.CTKEY ,B.PRODUCTLOT ,(SELECT CTCD_DTNAME FROM TWORK_MST_CTCD_DT WHERE CTKEY = I.CTKEY AND CTCD_HDKEY = 'LBNAME' AND LAKEY = 'KOR' AND CTCD_DTKEY = I.CTKEY) LBNM FROM TWORK_INFO_TA_DT A INNER JOIN TWORK_INFO_IVAT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.TO_IVATKEY = B.IVATKEY INNER JOIN TWORK_INFO_IB_DT C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.IBHDKEY = C.IBHDKEY AND A.IBDTKEY = C.IBDTKEY INNER JOIN TWORK_MST_IC F ON A.CTKEY = F.CTKEY AND A.OWKEY = F.OWKEY AND A.ICKEY = F.ICKEY INNER JOIN TWORK_INFO_IB_HD H ON A.OWKEY = H.OWKEY AND A.CTKEY = H.CTKEY AND A.IBHDKEY = H.IBHDKEY INNER JOIN TWORK_INFO_IVATXLCXULC I ON A.CTKEY = I.CTKEY AND A.OWKEY = I.OWKEY AND A.ICKEY = I.ICKEY AND A.TO_IVATKEY = I.IVATKEY LEFT JOIN TWORK_MST_ICUT D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND A.ICUTKEY = D.ICUTKEY LEFT JOIN TWORK_MST_ICUTXTYPE E ON A.OWKEY = E.OWKEY AND A.CTKEY = E.CTKEY AND A.ICUTKEY = E.ICUTKEY AND A.UOM = E.ICUTTYPE LEFT JOIN TWORK_MST_OW G ON A.OWKEY = G.OWKEY WHERE A.TA_DTTYPE = '60' AND A.CTKEY = #{ctkey} AND I.ULCKEY = 'NA'
AND A.IBHDKEY = #{ibhdkey}
AND A.IBDTKEY = #{ibdtkey}
AND A.IBDTKEY IN
#{ibtadtkeyList}
ORDER BY B.IVATKEY , B.PRODUCTLOT ,CFQTY DESC

SELECT A.IBHDKEY ,A.IBDTKEY ,A.OWKEY ,G.OWNAME ,A.ICKEY ,A.ICUTKEY ,1 AS LABELQTY ,I.TTQTY / E.ICUTQTY AS CFQTY ,A.UOM ,A.CTKEY || ';' || 'ICUTTYPE' ||';'|| A.UOM AS UOM_DESC ,A.WKSTATUS ,A.CTKEY || ';' || 'TA_WKSTATUS' ||';'|| A.WKSTATUS AS WKSTATUS_DESC ,A.TO_LCKEY ,A.TO_ULCKEY ,A.TO_IVATKEY ,B.PRODUCTDATE ,B.EXPIREDATE ,B.IBCONFIRMDATE ,C.COSTPRICE ,C.IBNRCD ,C.ATTRIBUTE2 ,A.CTKEY || ';' || 'PM012' ||';'|| C.IBNRCD AS IBNRCD_DESC ,F.ICNAME ,F.SPEC ,A.INSERTDATE ,A.INSERTURKEY ,A.UPDATEDATE ,A.UPDATEURKEY ,H.IBEXPECTDATE ,C.EXQTY - C.CFQTY AS RJQTY ,A.CTKEY ,B.PRODUCTLOT FROM TWORK_INFO_TA_DT A INNER JOIN TWORK_INFO_IVAT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.TO_IVATKEY = B.IVATKEY INNER JOIN TWORK_INFO_IB_DT C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.IBHDKEY = C.IBHDKEY AND A.IBDTKEY = C.IBDTKEY INNER JOIN TWORK_MST_IC F ON A.CTKEY = F.CTKEY AND A.OWKEY = F.OWKEY AND A.ICKEY = F.ICKEY INNER JOIN TWORK_INFO_IB_HD H ON A.OWKEY = H.OWKEY AND A.CTKEY = H.CTKEY AND A.IBHDKEY = H.IBHDKEY INNER JOIN TWORK_INFO_IVATXLCXULC I ON A.CTKEY = I.CTKEY AND A.OWKEY = I.OWKEY AND A.ICKEY = I.ICKEY AND A.TO_IVATKEY = I.IVATKEY LEFT JOIN TWORK_MST_ICUT D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND A.ICUTKEY = D.ICUTKEY LEFT JOIN TWORK_MST_ICUTXTYPE E ON A.OWKEY = E.OWKEY AND A.CTKEY = E.CTKEY AND A.ICUTKEY = E.ICUTKEY AND A.UOM = E.ICUTTYPE LEFT JOIN TWORK_MST_OW G ON A.OWKEY = G.OWKEY WHERE A.TA_DTTYPE = '60' AND A.CTKEY = #{ctkey} AND I.ULCKEY = 'NA' AND I.LCKEY = CASE WHEN C.ATTRIBUTE2 = '1' THEN CASE F.LOGGRPCD WHEN '1' THEN 'STAGE_C' WHEN '2' THEN 'STAGE_B' ELSE 'STAGE_A' END ELSE CASE F.LOGGRPCD WHEN '1' THEN 'STAGE_C_BOND' WHEN '2' THEN 'STAGE_B_BOND' ELSE 'STAGE_A_BOND' END END
AND A.IBHDKEY = #{ibhdkey}
AND A.IBDTKEY = #{ibdtkey}
AND A.IBDTKEY IN
#{ibtadtkeyList}
ORDER BY B.IVATKEY , B.PRODUCTLOT ,CFQTY DESC

mapper.select:
#{GRIDPAGING_ROWNUMTYPE_TOP}
	SELECT *
	  FROM (

	)



			ORDER BY #{colName} DESC


			ORDER BY #{colName} ASC



			ORDER BY UPDATEDATE DESC


#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

SELECT WKSTATUS
  FROM TWORK_INFO_IB_HD
 WHERE 
       CTKEY = #{ctkey}
   AND IBHDKEY IN	

		#{IBHDKEY_LIST}

SELECT * FROM ( SELECT A.IBHDKEY ,COUNT(1) AS ITEM ,SUBSTR(IBHDDATE,1,8) AS IBHDDATE FROM TWORK_INFO_IB_HD A ,TWORK_INFO_IB_DT B WHERE A.CTKEY = #{ctkey} AND A.CTKEY = B.CTKEY AND A.IBHDKEY = B.IBHDKEY AND B.WKSTATUS < '90' AND A.CTKEY = #{ctkey} AND A.IBHDDATE BETWEEN TO_CHAR(TO_DATE(#{sysdate}, 'YYYYMMDDHH24MISS') - #{ENABLEMAXBETWEENDAYS}, 'YYYYMMDDHH24MISS') AND TO_CHAR(TO_DATE(#{sysdate}, 'YYYYMMDDHH24MISS') + #{ENABLEMAXBETWEENDAYS}, 'YYYYMMDDHH24MISS')
AND A.ACKEY IS NULL
AND A.ACKEY = #{ackey}
GROUP BY A.IBHDKEY ,SUBSTR(A.IBHDDATE,1,8) )
#{MOBILE_MULTI_SORING}

SELECT A.EXQTY 
      ,A.CFQTY
      ,B.ICNAME 
      ,A.IBDTKEY
  FROM TWORK_INFO_IB_DT A 
      ,TWORK_MST_IC B 
 WHERE A.CTKEY = #{ctkey}
   AND A.IBHDKEY = #{ibhdkey}

	   AND B.ICKEY = #{ickey}


	   AND A.IBDTKEY = #{ibdtkey}

   AND A.ICKEY = B.ICKEY
   AND A.CTKEY = B.CTKEY
   AND A.OWKEY = B.OWKEY

SELECT A.CTKEY ,A.ICKEY ,A.TO_LCKEY ,SUM(A.QTY) AS CFQTY ,SUM(A.RJQTY) AS RJQTY ,A.TO_IVATKEY FROM TWORK_INFO_TA_DT A ,TWORK_INFO_IVAT B WHERE A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.TO_IVATKEY= B.IVATKEY AND A.CTKEY = #{ctkey} AND A.IBHDKEY = #{ibhdkey} AND A.IBDTKEY = #{ibdtkey} AND A.TO_LCKEY = #{to_lckey}
AND B.PRODUCTDATE = #{productdate,typeHandler=GmtDateTimeFormatTypeHandler}
AND B.PRODUCTDATE IS NULL
AND B.EXPIREDATE = #{expiredate ,typeHandler=GmtDateTimeFormatTypeHandler}
AND B.EXPIREDATE IS NULL
GROUP BY A.CTKEY ,A.ICKEY ,A.TO_LCKEY ,A.TO_IVATKEY

mapper.update:
		UPDATE TWORK_INFO_IB_DT 
		   SET AJQTY = #{ajqty}
		      ,GAPREASONCD = #{gapreasoncd}
			  ,UPDATEDATE  = #{sysdate}
			  ,UPDATEURKEY = #{surkey}
        WHERE CTKEY = #{ctkey}
          AND IBHDKEY = #{ibhdkey}
	      AND IBDTKEY = #{ibdtkey}

		UPDATE TWORK_INFO_IB_DT 
		   SET IBNRCD = #{ibnrcd}
		   	  ,UDF5 = #{udf5}
			  ,UPDATEDATE  = #{sysdate}
			  ,UPDATEURKEY = #{surkey}
        WHERE CTKEY = #{ctkey}
          AND IBHDKEY = #{ibhdkey}
	      AND IBDTKEY = #{ibdtkey}

mapper.select:
SELECT CASE WHEN 
                 TO_DATE(TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD'),'YYYYMMDD')
                 - TO_DATE(SUBSTR(IBCONFIRMDATE,1,8),'YYYYMMDD') > #{CLOSINGLIMITDATEORDER}
            THEN 'N' ELSE 'Y' 
        END AS LIMIT_UPDATEORDER
  FROM TWORK_INFO_IB_HD
 WHERE CTKEY = #{ctkey}
   AND IBHDKEY = #{ibhdkey}

SELECT COALESCE(MAX(CRTYPE), 'N')
FROM TWORK_INFO_ILBHS
WHERE CTKEY = #{ctkey}
  AND ILBHSKEY = #{ilbhskey}

SELECT X.*, Y.GROUP_SUM FROM( SELECT TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS') AS PRINT_DATE , A.EXTERNORDERKEY , A.IBEXPECTDATE , A.OWKEY , C.OWNAME , B.EXTERNORDERLINENUM , A.CTKEY || ';' || 'LOGGRPCD;' || D.LOGGRPCD AS LOGGRPCD_DESC , E.ICGRNAME , B.ICKEY , D.ICNAME , D.SPEC , A.CTKEY || ';' || 'ICUTTYPE;' || D.UOM AS UOM_DESC , B.EXQTY , A.EXTERNORDERKEY || B.EXTERNORDERLINENUM AS SCAN_CODE , A.CTKEY FROM TWORK_INFO_IB_HD A LEFT JOIN TWORK_INFO_IB_DT B ON A.OWKEY = B.OWKEY AND A.CTKEY = B.CTKEY AND A.IBHDKEY = B.IBHDKEY LEFT JOIN TWORK_MST_OW C ON A.OWKEY = C.OWKEY LEFT JOIN TWORK_MST_IC D ON B.OWKEY = D.OWKEY AND B.CTKEY = D.CTKEY AND B.ICKEY = D.ICKEY LEFT JOIN TWORK_MST_ICGR E ON D.OWKEY = E.OWKEY AND D.CTKEY = E.CTKEY AND D.ICGRKEY = E.ICGRKEY AND D.ICGRTYPE = E.ICGRTYPE ) X, ( SELECT A.EXTERNORDERKEY, A.OWKEY, A.CTKEY, SUM(B.EXQTY) AS GROUP_SUM FROM TWORK_INFO_IB_HD A LEFT JOIN TWORK_INFO_IB_DT B ON A.OWKEY = B.OWKEY AND A.CTKEY = B.CTKEY AND A.IBHDKEY = B.IBHDKEY GROUP BY ROLLUP (A.EXTERNORDERKEY, A.OWKEY, A.CTKEY) ) Y WHERE X.EXTERNORDERKEY = Y.EXTERNORDERKEY AND X.OWKEY = Y.OWKEY AND X.CTKEY = Y.CTKEY AND X.EXTERNORDERKEY IN
#{externorderkeyList}
ORDER BY CAST(X.EXTERNORDERLINENUM AS NUMERIC)
